import React, { useState, useEffect } from 'react';
import { io } from 'socket.io-client';
import './App.css';

function App() {
  const [socket, setSocket] = useState(null);
  const [playerName, setPlayerName] = useState('');
  const [nameSubmitted, setNameSubmitted] = useState(false);
  const [playerSymbol, setPlayerSymbol] = useState(null);
  const [roomId, setRoomId] = useState(null);
  const [gameState, setGameState] = useState(null);
  const [gameStatus, setGameStatus] = useState('Waiting for opponent...');
  const [disconnected, setDisconnected] = useState(false);

  // Initialize Socket.io connection
  useEffect(() => {
    const newSocket = io('/', {
      reconnection: true,
      reconnectionDelay: 1000,
      reconnectionDelayMax: 5000,
      reconnectionAttempts: 5
    });

    newSocket.on('connect', () => {
      console.log('Connected to server');
      setDisconnected(false);
    });

    newSocket.on('playerAssigned', (data) => {
      setPlayerSymbol(data.symbol);
      setRoomId(data.roomId);
      setGameState(data.gameState);
      console.log(`You are player ${data.symbol} in room ${data.roomId}`);
    });

    newSocket.on('gameStateUpdate', (state) => {
      setGameState(state);
      updateGameStatus(state);
    });

    newSocket.on('playerDisconnected', (data) => {
      setGameStatus(data.message);
      setDisconnected(true);
    });

    newSocket.on('disconnect', () => {
      setDisconnected(true);
      setGameStatus('Disconnected from server');
    });

    setSocket(newSocket);

    return () => {
      newSocket.disconnect();
    };
  }, []);

  // Update game status message
  const updateGameStatus = (state) => {
    if (!state) return;

    if (state.winner) {
      if (state.winner === 'draw') {
        setGameStatus("It's a Draw!");
      } else {
        const winnerName = state.players[state.winner].name;
        setGameStatus(`${winnerName} (${state.winner}) wins!`);
      }
    } else if (state.gameActive) {
      const currentPlayerName = state.players[state.currentPlayer].name;
      if (state.currentPlayer === playerSymbol) {
        setGameStatus('Your turn');
      } else {
        setGameStatus(`${currentPlayerName}'s turn`);
      }
    } else {
      setGameStatus('Waiting for opponent...');
    }
  };

  // Handle name submission
  const handleNameSubmit = (e) => {
    e.preventDefault();
    if (playerName.trim() && socket) {
      setNameSubmitted(true);
      socket.emit('joinGame', playerName);
    }
  };

  // Handle board cell click
  const handleCellClick = (index) => {
    if (
      socket &&
      gameState &&
      gameState.gameActive &&
      gameState.board[index] === null &&
      gameState.currentPlayer === playerSymbol
    ) {
      socket.emit('makeMove', index);
    }
  };

  // Handle game reset
  const handleResetGame = () => {
    if (socket) {
      socket.emit('resetGame');
    }
  };

  // Render player name input screen
  if (!nameSubmitted) {
    return (
      <div className="container">
        <div className="welcome-screen">
          <h1>Tic Tac Toe</h1>
          <p className="subtitle">Enter your name to join a game</p>
          <form onSubmit={handleNameSubmit}>
            <input
              type="text"
              placeholder="Enter your name"
              value={playerName}
              onChange={(e) => setPlayerName(e.target.value)}
              maxLength="20"
              disabled={!socket}
            />
            <button type="submit" disabled={!playerName.trim() || !socket}>
              {socket ? 'Join Game' : 'Connecting...'}
            </button>
          </form>
        </div>
      </div>
    );
  }

  // Render game screen
  return (
    <div className="container">
      <div className="game-screen">
        <h1>Tic Tac Toe</h1>

        <div className="game-info">
          <div className="player-info">
            <div className="player-card">
              <p className="player-name">You: {playerName}</p>
              <p className="player-symbol">{playerSymbol}</p>
              {gameState && gameState.players[playerSymbol] && (
                <p className="player-status">
                  {gameState.currentPlayer === playerSymbol ? '🔴 Your Turn' : '⚫ Waiting'}
                </p>
              )}
            </div>
            {gameState && gameState.players[playerSymbol === 'X' ? 'O' : 'X'] && (
              <div className="player-card opponent">
                <p className="player-name">
                  Opponent: {gameState.players[playerSymbol === 'X' ? 'O' : 'X'].name}
                </p>
                <p className="player-symbol">{playerSymbol === 'X' ? 'O' : 'X'}</p>
                <p className="player-status">
                  {gameState.currentPlayer === (playerSymbol === 'X' ? 'O' : 'X')
                    ? '🔴 Their Turn'
                    : '⚫ Waiting'}
                </p>
              </div>
            )}
          </div>

          <div className="game-status">
            <p className="status-text">{gameStatus}</p>
            <p className="room-info">Room: {roomId}</p>
            {disconnected && (
              <p className="disconnected-warning">⚠️ Connection Lost</p>
            )}
          </div>
        </div>

        <div className="board">
          {gameState &&
            gameState.board.map((cell, index) => (
              <div
                key={index}
                className={`cell ${cell ? `cell-${cell}` : ''} ${
                  gameState.currentPlayer === playerSymbol && !gameState.winner
                    ? 'clickable'
                    : ''
                }`}
                onClick={() => handleCellClick(index)}
              >
                {cell}
              </div>
            ))}
        </div>

        {gameState && gameState.winner && (
          <div className="reset-section">
            <button onClick={handleResetGame} className="reset-btn">
              Play Again
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

export default App;
